def get_icon(icon_key: str, size: str = "") -> str:
    """Return an inline SVG icon wrapped in a span.

    Resolves semantic aliases (from ICON_ALIASES) before looking up SVG_ICONS,
    so both ``get_icon('shield')`` and ``get_icon('safety_shield')`` work.

    Args:
        icon_key: Direct SVG_ICONS key or an alias from ICON_ALIASES
        size: Optional size class ('sm', 'lg', 'xl')

    Returns:
        HTML string with the wrapped SVG icon
    """
    svg_name = ICON_ALIASES.get(icon_key, icon_key)
    svg_content = SVG_ICONS.get(svg_name, SVG_ICONS.get("info", ""))
    size_class = f" {size}" if size else ""
    return f'<span class="icon{size_class}">{svg_content}</span>'
